# Generic fallback features by continent
CONTINENT_FEATURE = {
    "Africa": ("Inland Plateau", "plateau", "Inland savanna and highlands."),
    "Asia": ("Inland Plains", "plains", "Broad inland plains and river basins."),
    "Europe": ("Lowland Plains", "plains", "Rolling lowland countryside."),
    "North America": ("Coastal Lowlands", "plains", "Mixed coastal and inland lowlands."),
    "South America": ("Tropical Lowlands", "plains", "Tropical river basin lowlands."),
    "Oceania": ("Pacific Atolls", "atoll", "Low-lying Pacific coral atolls."),
    "Antarctica": ("Polar Ice Sheet", "ice sheet", "Continental ice cover."),
}

def main():
    path = Path("C:/Users/dglazier/source/Personal/mammas-place/data/countries.json")
    countries = json.loads(path.read_text(encoding="utf-8"))
    filled_from_dict = 0
    filled_generic = 0
    for c in countries:
        iso = c.get("iso2")
        if iso in DATA:
            c["landmarks"] = DATA[iso]["landmarks"]
            c["physicalFeatures"] = DATA[iso]["physicalFeatures"]
            filled_from_dict += 1
        else:
            cap = c.get("capital", c.get("name"))
            latlon = c.get("capitalLatLon") or [0, 0]
            c["landmarks"] = [{
                "name": f"Central {cap}",
                "description": f"Historic center of {cap}.",
                "fact": "",
                "latLon": latlon,
            }]
            feat_name, feat_type, feat_desc = CONTINENT_FEATURE.get(
                c.get("continent", ""), ("National Landscape", "landscape", "Country landscape.")
            )
            c["physicalFeatures"] = [{
                "name": feat_name,
                "type": feat_type,
                "description": feat_desc,
                "fact": "",
                "latLon": latlon,
            }]
            filled_generic += 1
    path.write_text(json.dumps(countries, indent=2, ensure_ascii=False), encoding="utf-8")
    print(f"Filled from dict: {filled_from_dict}")
    print(f"Filled generic:   {filled_generic}")
    print(f"Total countries:  {len(countries)}")

if __name__ == "__main__":
    main()
